import { environment, ZuploRequest, ZuploContext, RuntimeExtensions } from "@zuplo/runtime";

export async function runtimeInit(runtime: RuntimeExtensions) {
  runtime.notFoundHandler = async (
    request: ZuploRequest,
    context: ZuploContext
  ) => {
    const url = new URL(request.url);
    const path = url.pathname;

    const body = JSON.stringify({
      error: "Not Found",
      path: path,
      run_id: environment.ZEALT_RUN_ID,
    });

    return new Response(body, {
      status: 404,
      headers: {
        "Content-Type": "application/json",
        "X-Custom-404": "true",
      },
    });
  };
}
```

